sections.preambleSelect:
Se  (ETipSal = 0)
    Mensagem(Erro," 'Opção inválida para a lista!' ");

/********************** DEFINIÇÃO DO TÍTULO DO RELATÓRIO **********************/
Se  (ETipSal = 1)
    {
    AlteraControle("Descricao_Titulo", "Descrição", "Balancete por Período - Contábil");
    AlteraControle("Descricao_CCusto", "Imprimir", "Falso");
    AlteraControle("DHifem", "Imprimir", "Falso");
    AlteraControle("Descricao_DesCcu", "Imprimir", "Falso");
    AlteraControle("Cabecalho", "Altura", "157");         
    }
Senao
    AlteraControle("Descricao_Titulo", "Descrição", "Balancete por Período - Centro de Custo");

/***** PÁGINA OU FOLHA - DEFINE SE O RELATÓRIO VAI TER PÁGINAS OU FOLHAS ******/ 
Se  (EFolPag = 'P')
    AlteraControle("DFolPag","Descrição","Página:");
Senao
    AlteraControle("DFolPag","Descrição","Folha:");

xNumPag = 1;  

/****** NÚMERO PÁGINA/FOLHA - DEFINE A PÁGINA/FOLHA INICIAL DO RELATÓRIO ******/
Se  (ENumFol > 0)
    FNumPag = ENumFol;  
Senao
    FNumPag = 1;

Se  (ECcuIta = 'S')
    AlteraControle("Adicional_CCusto","Fonte",";Italico;;");

/*********** NÚMERO DO LIVRO - DEFINE O NÚMERO DO LIVRO IMPRESSO **************/      
Se  (ENumLiv > 0)
    FNumLiv = ENumLiv;

/************************* VALIDAÇÃO DAS DATAS ********************************/
Se  (EDatIni = 0)
    Mensagem(Erro," 'Data Inicial deve ser informada!' ");   
Se  (EDatFim = 0)
    Mensagem(Erro," 'Data Final deve ser informada!' "); 
Se  (EDatIni > EDatFim)
    Mensagem(Erro," 'Data inicial maior que data final!' ");

/*********** MONTAR ABRANGÊNCIA E VALIDA FILIAL - PRÉ SELEÇÃO *****************/
@- Monta abrangência de filial -@
MontaAbrangencia("E070FIL.CODFIL", ECodFil, xAbrFil);
@- Valida se não foi informada filial -@
Se  ((ETipOrd = 'N') e (xAbrFil = ""))
    Mensagem(Erro," 'Informe a Filial!' ");  

/****************************** EMPRESA ***************************************/
xSql = "SELECT E070EMP.CODEMP, E070EMP.NOMEMP " +
         "FROM E070EMP " +
        "WHERE E070EMP.CODEMP = :CODEMP";  
SQL_Criar (xCursor);
SQL_DefinirComando (xCursor, xSql);
SQL_DefinirInteiro (xCursor, "CODEMP", ECodEmp);      
SQL_AbrirCursor    (xCursor); 
Se  (SQL_EOF(xCursor) = 0)
    {
    SQL_RetornarFlutuante (xCursor, "CODEMP", xCodEmp);
              IntParaAlfa (xCodEmp, DCodEmp);
         SQL_RetornarAlfa (xCursor, "NOMEMP", DNomEmp);
    }
SQL_FecharCursor(xCursor);
SQL_Destruir(xCursor);

/********************************** FILIAL ************************************/
Se  (ETipOrd = 'S')                                                              /** SE FOR CONSOLIDADO **/
    {
    AlteraControle ("DConsolidado", "Imprimir", "Verdadeiro");
    AlteraControle ("DCodFil"     , "Imprimir", "Falso");
    AlteraControle ("DNomFil"     , "Imprimir", "Falso");
    AlteraControle ("DCNPJ"       , "Imprimir", "Falso");
    AlteraControle ("FNumCgc"     , "Imprimir", "Falso");
    }
Senao                                                                           /** SE NÃO FOR CONSOLIDADO **/
    {
    xSql = "SELECT E070FIL.CODFIL, E070FIL.NOMFIL, E070FIL.NUMCGC " +
             "FROM E070FIL " +
            "WHERE E070FIL.CODEMP = :CODEMP AND " + xAbrFil + " AND ";

    Se  (ETipSal = 1)                                                              @ ETipSal = 1 - Contábil @ 
        xSql = xSql + "EXISTS (SELECT 1 FROM E640LCT " +
                               "WHERE E640LCT.CODEMP = E070FIL.CODEMP AND " +
                                     "E640LCT.CODFIL = E070FIL.CODFIL AND " +
                                     "E640LCT.DATLCT >= :DATINI AND " +
                                     "E640LCT.DATLCT <= :DATFIM)";       
    Senao                                                                         @ ETipSal = 2 - Centro de Custo @  
        xSql = xSql + "EXISTS (SELECT 1 FROM E640LCT, E640RAT " +
                               "WHERE E640LCT.CODEMP = E070FIL.CODEMP AND " +
                                     "E640LCT.CODFIL = E070FIL.CODFIL AND " +
                                     "E640RAT.CODEMP = E070FIL.CODEMP AND " +
                                     "E640RAT.NUMLCT = E640LCT.NUMLCT AND " +
                                     "E640LCT.DATLCT >= :DATINI AND " +
                                     "E640LCT.DATLCT <= :DATFIM)";                                   
    SQL_Criar (xCursor);
    SQL_DefinirComando (xCursor, xSql);
    SQL_DefinirInteiro (xCursor, "CODEMP", ECodEmp);      
    SQL_DefinirData    (xCursor, "DATINI", EDatIni);
    SQL_DefinirData    (xCursor, "DATFIM", EDatFim);
    SQL_AbrirCursor    (xCursor);   

    SQL_RetornarFlutuante (xCursor, "NUMCGC", FNumCgc);                           /** RETORNA OS VALORES PARA O CABEÇALHO **/
    Se  (SQL_EOF(xCursor) = 0)
        {     
        SQL_RetornarFlutuante (xCursor, "CODFIL", xCodFil);
                  IntParaAlfa (xCodFil, DCodFil);
             SQL_RetornarAlfa (xCursor, "NOMFIL", DNomFil);
        SQL_RetornarFlutuante (xCursor, "NUMCGC", FNumCgc);
        }
    Senao
        {
        SQL_FecharCursor(xCursor);
        SQL_Destruir(xCursor);
        Mensagem(Erro," 'Não existem movimentos para o período informado!' ");
        } 
    SQL_FecharCursor(xCursor);
    SQL_Destruir(xCursor);   
    }     

Se  (EConLct = 'S') 
    {
    ConsistirLctoAContabilizar(ECodEmp,ECodFil,EDatIni,EDatFim,"",vQtdRegistros);
    Se  (vQtdRegistros > 0)
        {
        Res = Mensagem(Retorna, "Existem lançamentos que não foram contabilizados no período informado! Deseja Continuar? [&Sim, &Não]");
        Se  (Res > 0)
            Cancel(1);
        }
    }

Se  (ECcuIta = 'S')
    AlteraControle("Adicional_CCusto","Fonte",";ITÁLICO;;");

