/******************** FUNÇÃO P/ RETORNAR AS FILIAIS ****************************/
Funcao Fun_PercorrerFiliais(); 
  {
  xSqlFil = "SELECT E070FIL.CODFIL, E070FIL.NOMFIL, E070FIL.NUMCGC " +
              "FROM E070FIL " +
             "WHERE E070FIL.CODEMP = :CODEMP AND " + xAbrFil + 
         " ORDER BY E070FIL.CODFIL";
  SQL_Criar (xCursorFil);
  SQL_DefinirComando (xCursorFil, xSqlFil);
  SQL_DefinirInteiro (xCursorFil, "CODEMP", ECodEmp);      
  SQL_AbrirCursor    (xCursorFil); 
  Enquanto(SQL_EOF(xCursorFil) = 0)
    {
    SQL_RetornarFlutuante (xCursorFil, "CODFIL", xCodFil);
              IntParaAlfa (xCodFil, DCodFil);
              IntParaAlfa (xCodFil, xCodFilAlfa);
         SQL_RetornarAlfa (xCursorFil, "NOMFIL", DNomFil);
    SQL_RetornarFlutuante (xCursorFil, "NUMCGC", FNumCgc);

    Se  (xControleFilial = 1)
        ListaSecao("Adicional_SaltarPagina");

    xControleFilial = 1;

    se  ((xNovoCcu = 'N') e (DBTipo = "ORACLE")) 
        Fun_GerarBalanceteCcu();
    senao   
        Fun_GerarBalancete();

    SQL_Proximo(xCursorFil);  
    }
  SQL_FecharCursor(xCursorFil);
  SQL_Destruir(xCursorFil);
  } 

/************************** FUNÇÃO PRINCIPAL **********************************/
Funcao Fun_GerarBalancete();
  {
  ConverteDataToDB(EDatIni,xDatIni);
  ConverteDataToDB(EDatFim,xDatFim);

  Se  (ETipSal = 2)
      {
      Definir Lista xListaCcu;
      xListaCcu.DefinirCampos();                                                  @ Criando a lista a ser utilizada com os centros de custos @
      xListaCcu.AdicionarCampo("CodCcu", Alfa);                                   @ Codigo CCusto         @
      xListaCcu.AdicionarCampo("DesCcu", Alfa);                                   @ Descrição CCusto      @
      xListaCcu.EfetivarCampos();

      Definir Lista xListaValoresCcu;
      xListaValoresCcu.DefinirCampos();                                           @ Cria uma lista gravando os valores para cada centro de custo @ 
      xListaValoresCcu.AdicionarCampo("CodCcu", Alfa);                            @ Codigo CCusto         @
      xListaValoresCcu.AdicionarCampo("DesCcu", Alfa);                            @ Descrição CCusto      @
      xListaValoresCcu.AdicionarCampo("SalAnt", Numero);                          @ Saldo Anterior CCusto @
      xListaValoresCcu.AdicionarCampo("DebCcu", Numero);                          @ Debido CCusto         @
      xListaValoresCcu.AdicionarCampo("CreCcu", Numero);                          @ Credito CCusto        @
      xListaValoresCcu.AdicionarCampo("SalCcu", Numero);                          @ Saldo CCusto          @ 
      xListaValoresCcu.EfetivarCampos();

      Se  ((ESalCon = 'S') e (EAbrCcu <> ""))
          {
          Definir Lista xListaCcuPai;
          xListaCcuPai.DefinirCampos();                                             @ Criando a lista a ser utilizada com os centros de custos @
          xListaCcuPai.AdicionarCampo("CodCcu", Alfa);                              @ Codigo CCusto @
          xListaCcuPai.EfetivarCampos();      
          Fun_BuscarCcuPai();
          }

      Fun_BuscarCCustos();                                                          @ Centro de Custo @                                                                   
      }

  Fun_MontarFiltrosEAbrangencias();                                             @ Monta os filtros e abrangências que serão utilizados @

  Se  (ETipSal = 1)                                                              @-- Cria estrutura para buscar saldos anteriores --@   
      CarregarSaldoContabil(1, ECodEmp, xCodFilAlfa, "", EDatIni, EDatFim, 0, 0, 0, 1, 0, 0, 0);  @ Contábil @
  Senao
      CarregarSaldoContabil(8, ECodEmp, xCodFilAlfa, "", EDatIni, EDatFim, 0, 0, 0, 1, 0, 0, 0);  @ Centro de Custo @

  @ Carregar as contas do plano @
  xSql = "SELECT E045PLA.CLACTA, E045PLA.CTARED, E045PLA.DESCTA, E045PLA.ANASIN, E045PLA.NIVCTA, E045PLA.MSKGCC, " +
                "E045PLA.CLAPAR, E045PLA.CTAPAR, E045PLA.DESPAR " +  
           "FROM E045PLA " + xBuscarCtaSubordinadas +  
          "WHERE " + xLigacoes + xFilNivCta + xDefGruCta + xFilSitCta +                                                   
               " E045PLA.CODEMP = :CODEMP " + xLigacaoCtaSubordinada +                               
      " ORDER BY E045PLA.CLACTA";
  SQL_Criar(xCursor);   
  SQL_UsarAbrangencia(xCursor, 0);
  SQL_UsarSQLSenior2(xCursor,0);    
  SQL_DefinirComando(xCursor,xSql);
  SQL_DefinirInteiro(xCursor, "CODEMP", ECodEmp);    
  Se  (ENivCta > 0)
      SQL_DefinirInteiro(xCursor, "NIVCTA", ENivCta);                                                                      
  SQL_AbrirCursor(xCursor); 
  Enquanto(SQL_EOF(xCursor) = 0)
    {
    Fun_ZerarCampos();                                                          @ Zerar os valores campos para que não sejam impressos com dados da conta anterior @     

    SQL_RetornarAlfa     (xCursor, "ANASIN", xAnaSin);          
    SQL_RetornarAlfa     (xCursor, "CLACTA", xClaCta);
    SQL_RetornarAlfa     (xCursor, "DESCTA", xDesCta);
    SQL_RetornarInteiro  (xCursor, "NIVCTA", xNivCta); 
    SQL_RetornarFlutuante(xCursor, "CTARED", xCtaRed);
    SQL_RetornarAlfa     (xCursor, "MSKGCC", xMskGcc);
    SQL_RetornarFlutuante(xCursor, "CTAPAR", xCtaPar);
    SQL_RetornarAlfa     (xCursor, "CLAPAR", xClaPar);
    SQL_RetornarAlfa     (xCursor, "DESPAR", xDesPar);   

    @Exibição da Classificação paralela@
    se  ((ETipCta = 2) e (xClaPar <> "") e (xClaPar <> " "))
        DClaCta = xClaPar;
    senao
        ConverteMaskContab(xNivCta, xClaCta, xMskGcc, DClaCta);

    @Exibição da Conta paralela@
    se  ((ETipCta = 2) e (xCtaPar <> 0))
        DCtaRed = xCtaPar;
    senao
        DCtaRed = xCtaRed;      

    Fun_DefinirRecuo();                                                         @ Define o recuo da descrição da conta @                                                               
    Se  (ETipSal = 1)                                                            @-- Buscar valores do período --@
        {
        SaldoContabilCompleto(xCtaRed, "", 0, FDebCta, FCreCta, FSalCta, FSalAntCta);  @ Contábil @            
        Fun_ListarAdicional();                                                    @ Verifica se é necessário listar a conta @                     
        }
    Senao
        {         
        xListaValoresCcu.Limpar();                                                @ Limpa os dados existentes na lista @    

        Se  (xCtaRed <> xCtaRedOld)                                                @ Se trocou a conta lista o adicional novamente @
            {               
            Se  (ESalCon = 'S')        
                {
                SaldoContabilCompleto(xCtaRed, "", 0, FDebCta, FCreCta, FSalCta, FSalAntCta);  @ Contábil @

                Se  (EAbrCcu <> "")                                                    @ Caso tenha uma abrangência de centro de custo informada, pega o saldo contábil pelo centro de custo pai para não ocorrerem erros@
                    {
                    xListaCcuPai.Primeiro();
                    Enquanto (xListaCcuPai.FDA = 0)
                      {
                      xCodCcu = xListaCcuPai.CodCcu;              
                      SaldoContabilCompleto(xCtaRed, xCodCcu, 0, xDebMes, xCreMes, xSalCta, xSalAntCta);

                      @ Atualiza o saldo a cada laço para listar o adicional conta @          
                      FDebCta = FDebCta + xDebMes;
                      FCreCta = FCreCta + xCreMes;
                      FSalCta = FSalCta + xSalCta;
                      FSalAntCta = FSalAntCta + xSalAntCta;                           

                      xListaCcuPai.Proximo();
                      }
                    }
                }

            xListaCcu.Primeiro();
            Enquanto (xListaCcu.FDA = 0)                                            @ Percorre a lista dos Centros de Custo buscando os valroes para cada um e gravando na lista @
              {
              xCodCcu = xListaCcu.CodCcu;          
              SaldoContabilCompleto(xCtaRed, xCodCcu, 0, xDebMes, xCreMes, xSalCta, xSalAntCta);

              xListaValoresCcu.Adicionar();                                         @ Grava os valroes retornados em uma lista para não precisar buscá-los novamente @ 
              xListaValoresCcu.CodCcu = xCodCcu;           
              xListaValoresCcu.DesCcu = xListaCcu.DesCcu;  
              xListaValoresCcu.SalAnt = xSalAntCta;        
              xListaValoresCcu.DebCcu = xDebMes;           
              xListaValoresCcu.CreCcu = xCreMes;           
              xListaValoresCcu.SalCcu = xSalCta;           
              xListaValoresCcu.Gravar();     

              Se  ((EAbrCcu = "") ou (ESalCon = 'N'))                                                   @ Se não tiver abrangência de centro de custo, atualiza os saldos da conta para listar o adicional @
                  {                                    
                  FDebCta = FDebCta + xDebMes;
                  FCreCta = FCreCta + xCreMes;
                  FSalCta = FSalCta + xSalCta;
                  FSalAntCta = FSalAntCta + xSalAntCta;           
                  }

              xListaCcu.Proximo();            
              }
            }        

        xCtaRedOld = xCtaRed;      
        Fun_ListarAdicional();                                                    @ Verifica se é necessário listar a conta @

        Se  (xAnaSin = "A")
            {      
            xListaValoresCcu.Primeiro();
            Enquanto (xListaValoresCcu.FDA = 0)                                       @ Percorre a lista de centros de custos para listar o adicional CCusto @ 
              {                                                                                   
              DCodCcu    = xListaValoresCcu.CodCcu;                                   @ Atribui valor aos campos dos adicionais @
              DDesCcu    = xListaValoresCcu.DesCcu;
              FDebCcu    = xListaValoresCcu.DebCcu;
              FCreCcu    = xListaValoresCcu.CreCcu;
              FSalCcu    = xListaValoresCcu.SalCcu;
              FSalAntCcu = xListaValoresCcu.SalAnt;

              Se  ((FDebCcu <> 0) ou (FCreCcu <> 0) ou (FSalCcu <> 0) ou (FSalAntCcu <> 0)) @ Lista o adicional somente se existir valores @  
                  ListaSecao("Adicional_CCusto");

              xListaValoresCcu.Proximo();     
              }
            }
        }
    SQL_Proximo(xCursor); 
    }
  SQL_FecharCursor(xCursor);
  SQL_Destruir(xCursor);
  }

Funcao Fun_GerarBalanceteCcu();
  {
  Se  (ESalCon = 'S')
      Mensagem(Erro,"Parâmetro 'Considerar Saldo das Contas Contábeis não disponível para nova modalidade de conciliação por centro de custos!");

  @Inicializar@
  SldCtbFuncoes(1);

  @DefinirTipoSaldo@
  SldCtbDefParametro("TipSaldo","8");
  SldCtbDefParametro("AbrCcu", EAbrCcu);

  @Listar Somente Sintéticas@
  Se  (EAnaSin = 'N')          
      SldCtbDefParametro("LstAna", "S");  

  Se  (ESitCta <> 'T')
      Se  (ESitCta = 'A')      
          SldCtbDefParametro("SitCta", "A");
      Senao
          SldCtbDefParametro("SitCta", "I");    

  Definir Alfa xTemp;

  IntParaAlfa(ECodEmp, xTemp);
  SldCtbDefParametro("CodEmp", xTemp);

  SldCtbDefParametro("AbrFil", xCodFilAlfa);
  SldCtbDefParametro("DefGru", EDefGru);

  IntParaAlfa(ECtaRed, xTemp); 
  SldCtbDefParametro("CtaRed", xTemp);

  IntParaAlfa(EDatIni, xTemp); 
  SldCtbDefParametro("DatIni", xTemp);

  IntParaAlfa(EDatFim, xTemp); 
  SldCtbDefParametro("DatFim", xTemp);

  IntParaAlfa(ENivCta, xTemp);
  SldCtbDefParametro("NivCta", xTemp);

  SldCtbDefParametro("ComSaldoAnterior","1");
  SldCtbDefParametro("MesesAbertos","0");
  @SldCtbDefParametro("AnaCcu", "A");@

  SldCtbFuncoes(3); @Carregar@

  Definir Numero xCtaRedOld;  
  Definir Alfa xCodCcu; 
  Definir Numero xMesano;  
  Definir Alfa xClaCcu; 
  Definir Alfa xAnaCta; 
  Definir Alfa xAnaCcu; 
  Definir Numero xDebMes; 
  Definir Numero xCreMes; 
  Definir Numero xSalMes;
  Definir Alfa xCursor;

  Fun_ZerarCampos(); 
  SldCtbRetItemAtual(xCtaRed, xCodCcu, xMesano, xClaCta, xClaCcu, xAnaCta, xAnaCcu, xDebMes, xCreMes, xSalMes, xCtaRedOld);
  Enquanto(xCtaRed > 0)
    {
    Se  (xCodCcu = "")
        { @Seção Centro de Custos@ 
        FCreCta = xCreMes;
        FDebCta = xDebMes;
