/****************** Busca os valores C.Custo para o período *******************/                                      
Funcao Fun_BuscarCCustos();  
  {
  Definir Alfa xSqlCentroCustos;

  xSqlCentroCustos = ",(SELECT E640RAT.CODEMP, E640RAT.CODCCU " +
                         "FROM E640RAT " +
                        "WHERE E640RAT.CODEMP = :CODEMP AND " +
                              "E640RAT.SITRAT = 2 AND " +
                              "E640RAT.DATLCT <= :DATFIM";
  Se  (EAbrCcu <> "")
      {
      MontaAbrangencia("E044CCU.CODCCU", EAbrCcu, xFilCodCcu);
      xFilCodCcu = " AND "  + xFilCodCcu;

      xRetornoCCuSql = ",(SELECT E044CCU.CODEMP, E044CCU.CLACCU " +
                           "FROM E044CCU " +
                          "WHERE E044CCU.CODEMP = :CODEMP " + xFilCodCcu + 
                             " GROUP BY E044CCU.CODEMP, E044CCU.CLACCU) CCUPAI " ;
      Definir Alfa xVarConcat;                                                    @Variável para concatenar sql @                       
      Se  (DBTipo = "SQLSERVER")
          xVarConcat = "+";
      Senao
          xVarConcat = "||";

      xLigacaoCCuSql = "AND E044CCU.CLACCU LIKE CCUPAI.CLACCU "+ xVarConcat + " '%' " + 
                       "AND E044CCU.CODEMP = CCUPAI.CODEMP ";

      MontaAbrangencia("E640RAT.CODCCU", EAbrCcu, xFilCodCcu);
      xSqlCentroCustos = xSqlCentroCustos + " AND "  + xFilCodCcu;
      }   
  xSqlCentroCustos = xSqlCentroCustos + " GROUP BY E640RAT.CODEMP, E640RAT.CODCCU) CCUSTO ";

  xSqlAux = "SELECT E044CCU.CODCCU, E044CCU.DESCCU, E044CCU.CLACCU " + 
              "FROM E044CCU" + xSqlCentroCustos + xRetornoCCuSql +               
             "WHERE E044CCU.CODEMP = :CODEMP AND " +               
                   "E044CCU.ANASIN = 'A' AND " +
                   "E044CCU.CODEMP = CCUSTO.CODEMP AND " +
                   "E044CCU.CODCCU = CCUSTO.CODCCU "+ xLigacaoCCuSql +
         " GROUP BY E044CCU.CODCCU, E044CCU.DESCCU, E044CCU.CLACCU " +
         " ORDER BY E044CCU.CODCCU";
  SQL_Criar(xCursorAux);
  SQL_UsarAbrangencia(xCursorAux, 0);
  SQL_UsarSQLSenior2(xCursorAux,0);    
  SQL_DefinirComando(xCursorAux, xSqlAux);  
  SQL_DefinirInteiro(xCursorAux, "CODEMP", ECodEmp);
  SQL_DefinirData   (xCursorAux, "DATFIM", EDatFim);         
  SQL_AbrirCursor   (xCursorAux);
  Enquanto(SQL_EOF(xCursorAux) = 0)   
    {     
    SQL_RetornarAlfa(xCursorAux, "CODCCU", xCodCcu);                            @ Retorna todos os centros de custo analíticos e adiciona na lista @
    SQL_RetornarAlfa(xCursorAux, "DESCCU", xDesCcu);

    xListaCcu.Adicionar();
    xListaCcu.CodCcu = xCodCcu;
    xListaCcu.DesCcu = xDesCcu;
    xListaCcu.Gravar();                  

    SQL_proximo(xCursorAux);        
    }
  SQL_FecharCursor(xCursorAux);
  SQL_Destruir(xCursorAux);
  }

